import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class PathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input containing path traversal
        String basePath = "/var/www/files/"; // Base directory where files are stored

        String filePath = basePath + userInput; // Constructing file path using user input

        try {
            File file = new File(filePath);
            FileInputStream fis = new FileInputStream(file);

            // Reading contents of the file
            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

